files.src/math/add.ts:
export function add(value: number, step = 1): number {
  return value + step;
}

export function addMany(start: number, deltas: number[]): number {
  return deltas.reduce((acc, item) => add(acc, item), start);
}

files.tests/math_ops.test.ts:
import test from "node:test";
import assert from "node:assert/strict";
import { add, addMany } from "../src/index.js";

test("add default and custom step", () => {
  assert.equal(add(7), 8);
  assert.equal(add(3, 4), 7);
});

test("addMany handles sequences", () => {
  assert.equal(addMany(1, [2, 3, 4]), 10);
  assert.equal(addMany(10, [5, -3, -2]), 10);
});

